 22	  setSelectedClipId: Dispatch<SetStateAction<string | null>>;
 23	  setSelectedTrackId: Dispatch<SetStateAction<string | null>>;
 24	  rowHeight: number;
 25	  scale: number;
 26	  scaleWidth: number;
