 30	/** Fixed-position indicator elements reused across drag moves. */
 31	interface DropIndicatorEls {
 32	  row: HTMLDivElement;
 33	  line: HTMLDivElement;
 34	  ghost: HTMLDivElement;
 35	  ghostLabel: HTMLSpanElement;
 36	  label: HTMLDivElement;
 37	}
