 39	interface DragSession {
 40	  pointerId: number;
 41	  clipId: string;
 42	  sourceRowId: string;
 43	  sourceKind: TrackKind;
 44	  startClientX: number;
 45	  startClientY: number;
 46	  pointerOffsetX: number;
 47	  pointerOffsetY: number;
 48	  latestStart: number;
 49	  clipDuration: number;
 50	  clipEl: HTMLElement;
 51	  moveListener: (event: PointerEvent) => void;
 52	  upListener: (event: PointerEvent) => void;
 53	  cancelListener: (event: PointerEvent) => void;
 54	  /** Floating clone shown during cross-track drag. */
 55	  floatingGhostEl: HTMLElement | null;
 56	  /** Shared drop indicator elements (row highlight, position line, ghost outline, label). */
 57	  indicator: DropIndicatorEls | null;
 58	  editAreaEl: HTMLElement | null;
 59	  gridEl: HTMLElement | null;
