 65	export const useClipDrag = ({
 66	  timelineWrapperRef,
 67	  dataRef,
 68	  moveClipToRow,
 69	  createTrackAndMoveClip,
 70	  setSelectedClipId,
 71	  setSelectedTrackId,
 72	  rowHeight,
 73	  scale,
 74	  scaleWidth,
 75	  startLeft,
 76	}: UseCrossTrackDragOptions): void => {
 77	  const dragSessionRef = useRef<DragSession | null>(null);
 78	  const actionDragStateRef = useRef<ActionDragState | null>(null);
 79	  const crossTrackActiveRef = useRef(false);
 80	
 81	  useEffect(() => {
 82	    const wrapper = timelineWrapperRef.current;
 83	    if (!wrapper) {
 84	      return undefined;
 85	    }
 86	
 87	    // ── Indicator lifecycle ──────────────────────────────────────────
 88	
 89	    const ensureIndicator = (session: DragSession): DropIndicatorEls => {
 90	      if (session.indicator) return session.indicator;
 91	
 92	      const row = document.createElement('div');
 93	      row.className = 'drop-indicator-row';
 94	      row.style.cssText = 'position:fixed;pointer-events:none;z-index:99998;';
 95	
 96	      const line = document.createElement('div');
 97	      line.className = 'drop-indicator-line';
 98	      line.style.zIndex = '99999';
 99	
100	      const ghost = document.createElement('div');
101	      ghost.className = 'drop-indicator-ghost';
102	      ghost.style.zIndex = '99998';
103	
104	      const ghostLabel = document.createElement('span');
105	      ghostLabel.className = 'drop-indicator-ghost-label';
106	      ghost.appendChild(ghostLabel);
107	
108	      const label = document.createElement('div');
109	      label.className = 'drop-indicator-label';
110	      label.style.zIndex = '100000';
111	
112	      document.body.append(row, line, ghost, label);
113	      session.indicator = { row, line, ghost, ghostLabel, label };
114	      return session.indicator;
115	    };
116	
117	    const clearDropIndicators = (session: DragSession | null) => {
118	      if (session?.indicator) {
119	        session.indicator.row.remove();
120	        session.indicator.line.remove();
121	        session.indicator.ghost.remove();
122	        session.indicator.label.remove();
123	        session.indicator = null;
124	      }
125	      session?.editAreaEl?.classList.remove('drop-target-new-track');
126	      if (session?.floatingGhostEl) {
127	        session.floatingGhostEl.style.cursor = '';
128	      }
129	    };
130	
131	    const clearSession = (session: DragSession | null, deferDeactivate = false) => {
132	      if (!session) {
133	        actionDragStateRef.current = null;
134	        if (!deferDeactivate) {
135	          crossTrackActiveRef.current = false;
136	        }
137	        return;
138	      }
139	
140	      clearDropIndicators(session);
141	      session.floatingGhostEl?.remove();
142	      window.removeEventListener('pointermove', session.moveListener);
143	      window.removeEventListener('pointerup', session.upListener);
144	      window.removeEventListener('pointercancel', session.cancelListener);
145	      try {
146	        if (session.clipEl.hasPointerCapture(session.pointerId)) {
147	          session.clipEl.releasePointerCapture(session.pointerId);
148	        }
149	      } catch {
150	        // Pointer capture can already be released by the browser during teardown.
151	      }
152	
153	      dragSessionRef.current = null;
154	      actionDragStateRef.current = null;
155	      if (deferDeactivate) {
156	        window.requestAnimationFrame(() => {
157	          if (!dragSessionRef.current) {
158	            crossTrackActiveRef.current = false;
159	          }
160	        });
161	      } else {
162	        crossTrackActiveRef.current = false;
163	      }
164	    };
165	
166	    // ── Helpers ──────────────────────────────────────────────────────
167	
168	    const updateFloatingGhostPosition = (session: DragSession, event: PointerEvent) => {
169	      if (!session.floatingGhostEl) return;
170	      session.floatingGhostEl.style.left = `${event.clientX - session.pointerOffsetX}px`;
171	      session.floatingGhostEl.style.top = `${event.clientY - session.pointerOffsetY}px`;
172	    };
173	
174	    const getTimelineElements = () => {
175	      const nextWrapper = timelineWrapperRef.current;
176	      if (!nextWrapper) return { editAreaEl: null, gridEl: null };
177	      const editAreaEl = nextWrapper.querySelector<HTMLElement>('.timeline-editor-edit-area');
178	      return {
179	        editAreaEl,
180	        gridEl: editAreaEl?.querySelector<HTMLElement>('.ReactVirtualized__Grid')
181	          ?? nextWrapper.querySelector<HTMLElement>('.ReactVirtualized__Grid'),
182	      };
183	    };
184	
185	    const getDropStartTime = (session: DragSession, clientX: number): number => {
186	      const { editAreaEl, gridEl } = getTimelineElements();
187	      if (!editAreaEl || !gridEl) return session.latestStart;
188	      const pixelsPerSecond = scaleWidth / scale;
189	      const editAreaRect = editAreaEl.getBoundingClientRect();
190	      const actionLeft = clientX - editAreaRect.left + gridEl.scrollLeft - session.pointerOffsetX;
191	      return Math.max(0, (actionLeft - startLeft) / pixelsPerSecond);
192	    };
193	
194	    const createFloatingGhost = (clipEl: HTMLElement): HTMLElement => {
195	      const rect = clipEl.getBoundingClientRect();
196	      const el = clipEl.cloneNode(true) as HTMLElement;
197	      el.classList.add('cross-track-ghost');
198	      el.style.width = `${rect.width}px`;
199	      el.style.height = `${rect.height}px`;
200	      document.body.appendChild(el);
201	      return el;
202	    };
203	
204	    // ── Core: update all drop indicators (row, line, ghost, label) ──
205	
206	    const updateDropTarget = (session: DragSession, clientX: number, clientY: number) => {
207	      const current = dataRef.current;
208	      if (!current) return;
209	
210	      const { editAreaEl, gridEl } = getTimelineElements();
211	      session.editAreaEl = editAreaEl;
212	      session.gridEl = gridEl;
213	      if (!editAreaEl || !gridEl) return;
214	
215	      const editAreaRect = editAreaEl.getBoundingClientRect();
216	      const rowIndex = rawRowIndexFromY(clientY, editAreaRect.top, gridEl.scrollTop, rowHeight);
217	      const pixelsPerSecond = scaleWidth / scale;
218	      const scrollLeft = gridEl.scrollLeft;
219	
220	      // Reset
221	      session.targetRowId = null;
222	      session.createTrackOnDrop = false;
223	      editAreaEl.classList.remove('drop-target-new-track');
224	
225	      // Below all tracks → new track affordance
226	      if (rowIndex >= current.rows.length) {
227	        clearDropIndicators(session);
228	        session.createTrackOnDrop = true;
229	        editAreaEl.classList.add('drop-target-new-track');
230	        return;
231	      }
232	
233	      const targetTrack = current.tracks[rowIndex];
234	      if (!targetTrack) return;
235	
236	      const isReject = targetTrack.kind !== session.sourceKind;
237	      if (!isReject) {
238	        session.targetRowId = targetTrack.id;
239	      }
240	
241	      // Position the full indicator set
242	      const ind = ensureIndicator(session);
243	      const rowScreenTop = editAreaRect.top + rowIndex * rowHeight - gridEl.scrollTop;
244	      const clipScreenLeft = editAreaRect.left + startLeft + session.latestStart * pixelsPerSecond - scrollLeft;
245	      const clipWidthPx = Math.max(2, session.clipDuration * pixelsPerSecond);
246	      const clampedGhostWidth = Math.min(clipWidthPx, editAreaRect.right - clipScreenLeft);
247	      const ghostCenter = clipScreenLeft + clampedGhostWidth / 2;
248	
249	      // Row highlight
250	      ind.row.className = isReject ? 'drop-indicator-row drop-indicator-row--reject' : 'drop-indicator-row';
251	      ind.row.style.top = `${rowScreenTop}px`;
252	      ind.row.style.left = `${editAreaRect.left}px`;
253	      ind.row.style.width = `${editAreaRect.width}px`;
254	      ind.row.style.height = `${rowHeight}px`;
255	
256	      // Position line
257	      ind.line.style.left = `${ghostCenter}px`;
258	      ind.line.style.top = `${rowScreenTop}px`;
259	      ind.line.style.height = `${rowHeight}px`;
260	
261	      // Ghost outline
262	      ind.ghost.style.left = `${clipScreenLeft}px`;
263	      ind.ghost.style.top = `${rowScreenTop + 2}px`;
264	      ind.ghost.style.width = `${clampedGhostWidth}px`;
265	      ind.ghost.style.height = `${Math.max(0, rowHeight - 4)}px`;
266	      ind.ghostLabel.textContent = `${session.latestStart.toFixed(1)}s`;
267	
268	      // Label
269	      const trackLabel = targetTrack.label ?? targetTrack.id;
270	      ind.label.style.left = `${ghostCenter - 30}px`;
271	      ind.label.style.top = `${rowScreenTop - 16}px`;
272	      ind.label.textContent = `${trackLabel} · ${session.latestStart.toFixed(1)}s`;
273	
274	      if (isReject && session.floatingGhostEl) {
275	        session.floatingGhostEl.style.cursor = 'not-allowed';
276	      } else if (session.floatingGhostEl) {
277	        session.floatingGhostEl.style.cursor = '';
278	      }
279	    };
280	
281	    // ── Pointer handlers ─────────────────────────────────────────────
282	
283	    const handlePointerDown = (event: PointerEvent) => {
284	      if (event.button !== 0) return;
285	
286	      const clipTarget = event.target instanceof HTMLElement ? event.target.closest<HTMLElement>('.clip-action') : null;
287	      if (!clipTarget || (event.target instanceof HTMLElement && event.target.closest("[data-delete-clip='true']"))) return;
288	
289	      const clipId = clipTarget.dataset.clipId;
290	      const rowId = clipTarget.dataset.rowId;
291	      if (!clipId || !rowId) return;
292	
293	      const current = dataRef.current;
294	      const sourceTrack = current?.tracks.find((track) => track.id === rowId);
295	      const sourceRow = current?.rows.find((row) => row.id === rowId);
296	      const sourceAction = sourceRow?.actions.find((action) => action.id === clipId);
297	      if (!current || !sourceTrack || !sourceAction) return;
298	
299	      clearSession(dragSessionRef.current);
300	
301	      const clipRect = clipTarget.getBoundingClientRect();
302	      const initialStart = sourceAction.start;
303	      const clipDuration = sourceAction.end - sourceAction.start;
304	      actionDragStateRef.current = {
305	        rowId,
306	        initialStart,
307	        initialEnd: sourceAction.end,
308	        latestStart: initialStart,
309	        latestEnd: sourceAction.end,
310	      };
311	
312	      const handlePointerMove = (moveEvent: PointerEvent) => {
313	        const session = dragSessionRef.current;
314	        if (!session || moveEvent.pointerId !== session.pointerId) return;
315	
316	        const dx = moveEvent.clientX - session.startClientX;
317	        const dy = moveEvent.clientY - session.startClientY;
318	        const distance = Math.sqrt(dx * dx + dy * dy);
319	
320	        // Don't show anything until the pointer actually moves (avoids flash on click)
321	        if (!session.hasMoved && distance < DRAG_THRESHOLD_PX) return;
322	
323	        // First move past threshold — capture the pointer so we own all subsequent events
324	        // and the timeline library can't start its own competing drag.
325	        if (!session.hasMoved) {
326	          session.hasMoved = true;
327	          try { session.clipEl.setPointerCapture(session.pointerId); } catch { /* ok */ }
328	        }
329	
330	        // Prevent default on all moves once dragging to stop the library's handler
331	        moveEvent.preventDefault();
332	
333	        // Update time position
334	        const latestStart = getDropStartTime(session, moveEvent.clientX);
335	        session.latestStart = latestStart;
336	        const dragState = actionDragStateRef.current;
337	        if (dragState) {
338	          const dur = dragState.initialEnd - dragState.initialStart;
339	          dragState.latestStart = latestStart;
340	          dragState.latestEnd = latestStart + dur;
341	        }
342	
343	        // Activate cross-track mode (floating ghost) on vertical threshold
344	        if (!crossTrackActiveRef.current && Math.abs(dy) >= 10) {
345	          crossTrackActiveRef.current = true;
346	          session.floatingGhostEl = createFloatingGhost(session.clipEl);
347	          updateFloatingGhostPosition(session, moveEvent);
348	        }
349	
350	        if (crossTrackActiveRef.current) {
351	          updateFloatingGhostPosition(session, moveEvent);
352	        }
353	
354	        // Always show the drop indicator (row highlight + position line + ghost + label)
355	        updateDropTarget(session, moveEvent.clientX, moveEvent.clientY);
356	      };
357	
358	      const handlePointerUp = (upEvent: PointerEvent) => {
359	        const session = dragSessionRef.current;
360	        if (!session || upEvent.pointerId !== session.pointerId) return;
361	
362	        const nextStart = actionDragStateRef.current?.latestStart ?? session.latestStart;
363	        if (crossTrackActiveRef.current) {
364	          upEvent.preventDefault();
365	          if (session.createTrackOnDrop) {
366	            createTrackAndMoveClip(session.clipId, session.sourceKind, nextStart);
367	          } else if (session.targetRowId) {
368	            moveClipToRow(session.clipId, session.targetRowId, nextStart);
369	            setSelectedTrackId(session.targetRowId);
370	          } else {
371	            moveClipToRow(session.clipId, session.sourceRowId, nextStart);
372	            setSelectedTrackId(session.sourceRowId);
373	          }
374	          setSelectedClipId(session.clipId);
375	          clearSession(session, true);
376	          return;
377	        }
378	
379	        // Same-row move — apply the horizontal position change
380	        if (session.hasMoved) {
381	          moveClipToRow(session.clipId, session.sourceRowId, nextStart);
382	        }
383	        setSelectedClipId(session.clipId);
384	        setSelectedTrackId(session.sourceRowId);
385	        clearSession(session);
386	      };
387	
388	      const handlePointerCancel = (cancelEvent: PointerEvent) => {
389	        const session = dragSessionRef.current;
390	        if (!session || cancelEvent.pointerId !== session.pointerId) return;
391	        clearSession(session);
392	      };
393	
394	      dragSessionRef.current = {
395	        pointerId: event.pointerId,
396	        clipId,
397	        sourceRowId: rowId,
398	        sourceKind: sourceTrack.kind,
399	        startClientX: event.clientX,
400	        startClientY: event.clientY,
401	        pointerOffsetX: event.clientX - clipRect.left,
402	        pointerOffsetY: event.clientY - clipRect.top,
403	        latestStart: initialStart,
404	        clipDuration,
405	        clipEl: clipTarget,
406	        moveListener: handlePointerMove,
407	        upListener: handlePointerUp,
408	        cancelListener: handlePointerCancel,
409	        floatingGhostEl: null,
410	        indicator: null,
411	        editAreaEl: null,
412	        gridEl: null,
413	        targetRowId: null,
414	        createTrackOnDrop: false,
415	        hasMoved: false,
416	      };
417	
418	      window.addEventListener('pointermove', handlePointerMove);
419	      window.addEventListener('pointerup', handlePointerUp);
420	      window.addEventListener('pointercancel', handlePointerCancel);
421	    };
422	
423	    const handleBlur = () => {
424	      clearSession(dragSessionRef.current);
425	    };
426	
427	    // Use capture phase so this fires BEFORE ClipAction's stopPropagation
428	    wrapper.addEventListener('pointerdown', handlePointerDown, true);
429	    window.addEventListener('blur', handleBlur);
430	    return () => {
431	      wrapper.removeEventListener('pointerdown', handlePointerDown, true);
432	      window.removeEventListener('blur', handleBlur);
433	      clearSession(dragSessionRef.current);
434	    };
435	  }, [
436	    createTrackAndMoveClip,
437	    dataRef,
438	    moveClipToRow,
439	    rowHeight,
440	    scale,
441	    scaleWidth,
442	    setSelectedClipId,
443	    setSelectedTrackId,
444	    startLeft,
445	    timelineWrapperRef,
446	  ]);
447	};

