114	function buildDataFromCurrentRegistry(
115	  config: TimelineConfig,
116	  current: TimelineData,
117	): TimelineData {
118	  const rowData = configToRows(config);
119	  const resolvedConfig = {
120	    output: { ...config.output },
121	    tracks: config.tracks ?? [],
122	    clips: config.clips.map((clip) => ({
123	      ...clip,
124	      assetEntry: clip.asset ? current.resolvedConfig.registry[clip.asset] : undefined,
125	    })),
126	    registry: { ...current.resolvedConfig.registry },
127	  };
128	
129	  return {
130	    config,
131	    registry: { ...current.registry },
132	    resolvedConfig,
133	    rows: rowData.rows,
134	    meta: rowData.meta,
135	    effects: rowData.effects,
136	    assetMap: Object.fromEntries(
137	      Object.entries(current.registry.assets ?? {}).map(([assetId, entry]) => [assetId, entry.file]),
138	    ),
139	    output: { ...config.output },
140	    tracks: config.tracks ?? [],
141	    clipOrder: rowData.clipOrder,
142	    signature: getConfigSignature(resolvedConfig),
143	  };
144	}
