import { useCallback, useLayoutEffect, useRef } from 'react';
import type { TimelineAction, TimelineRow } from '@xzdarcy/timeline-engine';
import { useProjectSelectionContext } from '@/shared/contexts/ProjectContext';
import { getGenerationDropData } from '@/shared/lib/dnd/dragDrop';
import {
  getVisualTracks,
  splitClipAtPlayhead,
  toggleClipMute,
  updateClipInConfig,
} from '@/tools/video-editor/lib/editor-utils';
import {
  buildRowTrackPatches,
  updateClipOrder,
} from '@/tools/video-editor/lib/coordinate-utils';
import { useAssetManagement } from '@/tools/video-editor/hooks/useAssetManagement';
import { useClipResize } from '@/tools/video-editor/hooks/useClipResize';
import type { DragCoordinator } from '@/tools/video-editor/hooks/useDragCoordinator';
import { useExternalDrop } from '@/tools/video-editor/hooks/useExternalDrop';
import {
  type ClipMeta,
  type TimelineData,
} from '@/tools/video-editor/lib/timeline-data';
